const folderId = "<folder-id>";
const includeTimestamp = false;
if (!folderId || folderId.includes("<folder-id>")) {
  console.log("Set folderId to a Google Drive folder id before running this cell.");
} else {
  try {
    const nb = runme.getCurrentNotebook();
    if (!nb) {
      throw new Error("No active notebook handle available.");
    }
    const sourceName = (typeof nb.getName === "function" && nb.getName()) || "google-drive-appkernel-cookbook";
    const baseName = sourceName.replace(/\.(json|runme\.md|md)$/i, "");
    let fileName = `${baseName}-copy.json`;
    if (includeTimestamp) {
      const now = new Date();
      const pad = (n) => String(n).padStart(2, "0");
      const timestamp = `${now.getFullYear()}${pad(now.getMonth() + 1)}${pad(now.getDate())}-${pad(now.getHours())}${pad(now.getMinutes())}${pad(now.getSeconds())}`;
      fileName = `${baseName}-copy-${timestamp}.json`;
    }
    const result = await drive.saveAsCurrentNotebook(folderId, fileName);
    console.log(result);
    console.log("This tab is now pointing at the new Drive-backed copy.");
  } catch (err) {
    console.error("Failed to save notebook as a Google Drive copy", { error: String(err) });
    throw err;
  }
}

console.log({
  hasDrive: typeof drive === "object",
  hasDriveCreate: typeof drive?.create,
  hasDriveUpdate: typeof drive?.update,
  hasGoogleClientManager: typeof googleClientManager === "object",
  hasOidc: typeof oidc === "object",
  hasApp: typeof app === "object",
  hasRunme: typeof runme === "object",
});

const configUrl = app.getDefaultConfigUrl();
console.log(`Applying config from ${configUrl}`);
try {
  const applied = await app.setConfig(configUrl);
  console.log({ applied: true, warnings: applied?.warnings ?? [] });
} catch (err) {
  console.log({ applied: false, error: String(err) });
}

const folderId = "<folder-id>";
if (!folderId || folderId.includes("<folder-id>")) {
  console.log("Set folderId before running this cell.");
} else {
  const fileId = await drive.create(folderId, `runme-drive-demo-${Date.now()}.md`);
  console.log({ fileId });
}

const fileId = "<file-id>";
if (!fileId || fileId.includes("<file-id>")) {
  console.log("Set fileId before running this cell.");
} else {
  const content = [
    "# Runme Google Drive Demo",
    "",
    "Updated from an AppKernel JS cell.",
    `Timestamp: ${new Date().toISOString()}`,
  ].join("\\n");
  await drive.update(fileId, new TextEncoder().encode(content));
  console.log({ updated: true, fileId });
}

const folderId = "<folder-id>";
if (!folderId || folderId.includes("<folder-id>")) {
  console.log("Set folderId before running this cell.");
} else {
  const fileId = await drive.create(folderId, `runme-demo-${Date.now()}.md`);
  const content = [
    "# Hello Google Drive",
    "",
    "Created and written from an AppKernel JS cell.",
    `Timestamp: ${new Date().toISOString()}`,
  ].join("\\n");
  await drive.update(fileId, new TextEncoder().encode(content));
  console.log({ fileId, status: "ok" });
}
